import { describe, expect, it } from "vitest";
import { stft, istft, type STFTConfig } from "../src/audio-stft";

function lcg(seed: number) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff - 0.5;
  };
}

function rmse(a: Float32Array, b: Float32Array): number {
  if (a.length !== b.length) {
    throw new Error(`rmse: length mismatch ${a.length} vs ${b.length}`);
  }
  let sum = 0;
  for (let i = 0; i < a.length; i++) {
    const d = a[i]! - b[i]!;
    sum += d * d;
  }
  return Math.sqrt(sum / a.length);
}

function trimCenter(x: Float32Array, count: number): Float32Array {
  if (count > x.length) {
    throw new Error(`trimCenter: count ${count} > length ${x.length}`);
  }
  const start = Math.floor((x.length - count) / 2);
  return x.subarray(start, start + count);
}

describe("audio-stft", () => {
  it("round-trips a sine wave with low RMSE on the central window", () => {
    const N = 8192;
    const sr = 16000;
    const freq = 440;
    const audio = new Float32Array(N);
    for (let t = 0; t < N; t++) {
      audio[t] = Math.sin((2 * Math.PI * freq * t) / sr);
    }
    const config: STFTConfig = { nFft: 512, hopLength: 128 };
    const spec = stft(audio, config);
    const recovered = istft({
      magnitude: spec.magnitude,
      phase: spec.phase,
      nFrames: spec.nFrames,
      config,
    });

    // Trim to a common interior length to avoid edge effects.
    const common = Math.min(audio.length, recovered.length);
    const aTrim = trimCenter(audio.subarray(0, common), 4096);
    const bTrim = trimCenter(recovered.subarray(0, common), 4096);
    const err = rmse(aTrim, bTrim);
    expect(err).toBeLessThan(1e-3);
  });

  it("round-trips white noise with low RMSE on the central window", () => {
    const N = 4096;
    const rand = lcg(0xdeadbeef);
    const audio = new Float32Array(N);
    for (let i = 0; i < N; i++) {
      audio[i] = rand();
    }
    const config: STFTConfig = { nFft: 256, hopLength: 64 };
    const spec = stft(audio, config);
    const recovered = istft({
      magnitude: spec.magnitude,
      phase: spec.phase,
      nFrames: spec.nFrames,
      config,
    });

    const common = Math.min(audio.length, recovered.length);
    const aTrim = trimCenter(audio.subarray(0, common), 2048);
    const bTrim = trimCenter(recovered.subarray(0, common), 2048);
    const err = rmse(aTrim, bTrim);
    expect(err).toBeLessThan(1e-3);
  });

  it("STFT magnitude peaks at the bin nearest the source frequency", () => {
    const N = 4096;
    const sr = 16000;
    const freq = 1000;
    const audio = new Float32Array(N);
    for (let t = 0; t < N; t++) {
      audio[t] = Math.sin((2 * Math.PI * freq * t) / sr);
    }
    const config: STFTConfig = { nFft: 512, hopLength: 128 };
    const spec = stft(audio, config);

    // Bin width = sr / nFft = 16000 / 512 = 31.25 Hz; 1000Hz lands at bin 32.
    const expectedBin = Math.round((freq * config.nFft) / sr);
    const middleFrame = Math.floor(spec.nFrames / 2);
    const rowStart = middleFrame * spec.nFreqs;

    let argmax = 0;
    let best = -Infinity;
    for (let k = 0; k < spec.nFreqs; k++) {
      const m = spec.magnitude[rowStart + k]!;
      if (m > best) {
        best = m;
        argmax = k;
      }
    }
    expect(Math.abs(argmax - expectedBin)).toBeLessThanOrEqual(1);
  });

  describe("validation", () => {
    it("throws RangeError when nFft is not a power of two", () => {
      const audio = new Float32Array(2048);
      expect(() => stft(audio, { nFft: 500, hopLength: 100 })).toThrow(RangeError);
    });

    it("throws RangeError when hopLength <= 0", () => {
      const audio = new Float32Array(2048);
      expect(() => stft(audio, { nFft: 512, hopLength: 0 })).toThrow(RangeError);
      expect(() => stft(audio, { nFft: 512, hopLength: -10 })).toThrow(RangeError);
    });

    it("throws RangeError when hopLength > nFft", () => {
      const audio = new Float32Array(2048);
      expect(() => stft(audio, { nFft: 512, hopLength: 1024 })).toThrow(RangeError);
    });

    it("throws RangeError when audio is shorter than nFft", () => {
      const audio = new Float32Array(256);
      expect(() => stft(audio, { nFft: 512, hopLength: 128 })).toThrow(RangeError);
    });
  });

  it("produces consistent shapes between stft and istft", () => {
    const N = 4096;
    const audio = new Float32Array(N);
    for (let i = 0; i < N; i++) {
      audio[i] = Math.sin((2 * Math.PI * 200 * i) / 16000);
    }
    const config: STFTConfig = { nFft: 512, hopLength: 128 };
    const spec = stft(audio, config);

    // Contract: nFrames = floor((audio.length - nFft) / hopLength) + 1.
    const expectedFrames = Math.floor((N - config.nFft) / config.hopLength) + 1;
    expect(spec.nFrames).toBe(expectedFrames);
    expect(spec.nFrames).toBe(29);
    expect(spec.nFreqs).toBe((config.nFft >> 1) + 1);
    expect(spec.magnitude.length).toBe(spec.nFrames * spec.nFreqs);
    expect(spec.phase.length).toBe(spec.nFrames * spec.nFreqs);

    const recovered = istft({
      magnitude: spec.magnitude,
      phase: spec.phase,
      nFrames: spec.nFrames,
      config,
    });

    // Contract: output length = (nFrames - 1) * hopLength + nFft.
    const expectedLen = (spec.nFrames - 1) * config.hopLength + config.nFft;
    expect(recovered.length).toBe(expectedLen);
    expect(recovered.length).toBe(4096);
  });
});
